#!/bin/bash

ARCHIVE_DIR="/archive"

if [ -z "$1" ]; then
  echo "Usage: $0 <logfile>"
  exit 1
fi

LOGFILE=$1

mkdir -p "$ARCHIVE_DIR/$LOGFILE"
cp "/var/log/$LOGFILE" "$ARCHIVE_DIR/$LOGFILE"